<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
    margin: 0;
    background: #f4f5f7;
    color: #222;
  }
  .wrap {
    max-width: 720px;
    margin: 0 auto;
    padding: 1.5rem 1rem 3rem;
  }
  h1 { font-size: 1.4rem; margin: 0 0 1rem; }
  h2 { font-size: 1.05rem; margin: 0 0 .6rem; }
  section {
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 1rem;
    margin-bottom: 1rem;
  }
  form .fields {
    display: flex;
    flex-wrap: wrap;
    gap: .75rem;
    align-items: flex-end;
  }
  label {
    display: flex;
    flex-direction: column;
    font-size: .85rem;
    gap: .25rem;
    font-weight: 600;
  }
  input, select, button {
    font: inherit;
    padding: .4rem .5rem;
    border: 1px solid #bbb;
    border-radius: 5px;
  }
  input:focus, select:focus { outline: 2px solid #4a7dff; outline-offset: 1px; }
  button {
    cursor: pointer;
    background: #2f6fed;
    color: #fff;
    border: none;
    font-weight: 600;
  }
  button:hover { background: #2258c7; }
  #form-error {
    color: #b00020;
    font-size: .9rem;
    min-height: 1.2em;
    margin-top: .5rem;
  }
  .filters {
    display: flex;
    flex-wrap: wrap;
    gap: .75rem;
    align-items: flex-end;
  }
  #expense-list { margin-top: .5rem; }
  .expense {
    display: flex;
    align-items: center;
    gap: .75rem;
    padding: .5rem .25rem;
    border-bottom: 1px solid #eee;
  }
  .expense:last-child { border-bottom: none; }
  .exp-amount { font-weight: 700; min-width: 5.5em; text-align: right; }
  .exp-cat {
    background: #eef2ff;
    border-radius: 4px;
    padding: .1rem .5rem;
    font-size: .85rem;
    text-transform: capitalize;
  }
  .exp-date { font-size: .9rem; color: #555; min-width: 6.5em; }
  .exp-note { flex: 1; font-size: .9rem; color: #444; overflow-wrap: anywhere; }
  .exp-del {
    background: #e5484d;
    padding: .25rem .6rem;
    font-size: .85rem;
  }
  .exp-del:hover { background: #c0393d; }
  .totals { display: flex; flex-wrap: wrap; gap: .75rem; align-items: baseline; }
  .total-line { font-size: 1.1rem; font-weight: 700; margin-bottom: .5rem; }
  #total { font-variant-numeric: tabular-nums; }
  .cat-total {
    background: #f0f0f0;
    border-radius: 5px;
    padding: .3rem .6rem;
    font-size: .9rem;
    text-transform: capitalize;
  }
  .empty { color: #777; font-style: italic; padding: .5rem 0; }
</style>
</head>
<body>
<div class="wrap">
  <h1>Personal Expense Tracker</h1>

  <section>
    <h2>Add expense</h2>
    <form id="expense-form" novalidate>
      <div class="fields">
        <label>Amount
          <input type="number" id="amount" step="0.01" min="0" placeholder="0.00">
        </label>
        <label>Category
          <select id="category">
            <option value="groceries">groceries</option>
            <option value="transport">transport</option>
            <option value="bills">bills</option>
            <option value="fun">fun</option>
          </select>
        </label>
        <label>Date
          <input type="date" id="date">
        </label>
        <label>Note (optional)
          <input type="text" id="note" placeholder="e.g. weekly shop">
        </label>
        <button type="submit" id="add-expense">Add expense</button>
      </div>
      <div id="form-error" role="alert"></div>
    </form>
  </section>

  <section>
    <h2>Filters</h2>
    <div class="filters">
      <label>Category
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </label>
      <label>From
        <input type="date" id="filter-from">
      </label>
      <label>To
        <input type="date" id="filter-to">
      </label>
      <button type="button" id="clear-filters">Clear filters</button>
    </div>
  </section>

  <section>
    <h2>Summary</h2>
    <div class="total-line">Total (visible): <span id="total">0.00</span></div>
    <div class="totals" id="cat-totals"></div>
  </section>

  <section>
    <h2>Expenses</h2>
    <div id="expense-list"></div>
  </section>
</div>

<script>
(function () {
  'use strict';

  var STORAGE_KEY = 'expense-tracker-expenses';
  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  var expenses = load();

  var amountEl = document.getElementById('amount');
  var categoryEl = document.getElementById('category');
  var dateEl = document.getElementById('date');
  var noteEl = document.getElementById('note');
  var formEl = document.getElementById('expense-form');
  var errorEl = document.getElementById('form-error');

  var filterCatEl = document.getElementById('filter-category');
  var filterFromEl = document.getElementById('filter-from');
  var filterToEl = document.getElementById('filter-to');
  var clearFiltersEl = document.getElementById('clear-filters');

  var listEl = document.getElementById('expense-list');
  var totalEl = document.getElementById('total');
  var catTotalsEl = document.getElementById('cat-totals');

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed.filter(function (e) {
        return e && typeof e.amount === 'number' && isFinite(e.amount) &&
               typeof e.category === 'string' && typeof e.date === 'string';
      });
    } catch (err) {
      return [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (err) { /* storage unavailable; app still works in-memory */ }
  }

  function visibleExpenses() {
    var cat = filterCatEl.value;
    var from = filterFromEl.value;
    var to = filterToEl.value;
    return expenses.filter(function (e) {
      if (cat !== 'all' && e.category !== cat) return false;
      if (from && e.date < from) return false;
      if (to && e.date > to) return false;
      return true;
    });
  }

  function render() {
    var visible = visibleExpenses();

    listEl.innerHTML = '';
    if (visible.length === 0) {
      var empty = document.createElement('div');
      empty.className = 'empty';
      empty.textContent = expenses.length === 0
        ? 'No expenses yet. Add one above.'
        : 'No expenses match the current filters.';
      listEl.appendChild(empty);
    } else {
      visible.forEach(function (e) {
        var row = document.createElement('div');
        row.className = 'expense';

        var amt = document.createElement('span');
        amt.className = 'exp-amount';
        amt.textContent = e.amount.toFixed(2);

        var cat = document.createElement('span');
        cat.className = 'exp-cat';
        cat.textContent = e.category;

        var date = document.createElement('span');
        date.className = 'exp-date';
        date.textContent = e.date;

        var note = document.createElement('span');
        note.className = 'exp-note';
        note.textContent = e.note || '';

        var del = document.createElement('button');
        del.type = 'button';
        del.className = 'exp-del';
        del.textContent = 'Delete';
        del.addEventListener('click', function () {
          var idx = expenses.indexOf(e);
          if (idx !== -1) {
            expenses.splice(idx, 1);
            save();
            render();
          }
        });

        row.appendChild(amt);
        row.appendChild(cat);
        row.appendChild(date);
        row.appendChild(note);
        row.appendChild(del);
        listEl.appendChild(row);
      });
    }

    var total = visible.reduce(function (sum, e) { return sum + e.amount; }, 0);
    totalEl.textContent = total.toFixed(2);

    catTotalsEl.innerHTML = '';
    CATEGORIES.forEach(function (c) {
      var catSum = visible.reduce(function (sum, e) {
        return e.category === c ? sum + e.amount : sum;
      }, 0);
      var chip = document.createElement('span');
      chip.className = 'cat-total';
      chip.setAttribute('data-cat', c);
      chip.textContent = c + ': ' + catSum.toFixed(2);
      catTotalsEl.appendChild(chip);
    });
  }

  formEl.addEventListener('submit', function (ev) {
    ev.preventDefault();

    var rawAmount = amountEl.value.trim();
    var amount = parseFloat(rawAmount);
    var date = dateEl.value;

    if (rawAmount === '' || isNaN(amount) || !isFinite(amount)) {
      errorEl.textContent = 'Please enter a valid numeric amount.';
      return;
    }
    if (amount <= 0) {
      errorEl.textContent = 'Amount must be greater than zero.';
      return;
    }
    if (!date) {
      errorEl.textContent = 'Please choose a date.';
      return;
    }

    expenses.unshift({
      amount: Math.round(amount * 100) / 100,
      category: categoryEl.value,
      date: date,
      note: noteEl.value.trim()
    });
    save();

    errorEl.textContent = '';
    amountEl.value = '';
    noteEl.value = '';

    render();
    amountEl.focus();
  });

  filterCatEl.addEventListener('change', render);
  filterFromEl.addEventListener('change', render);
  filterFromEl.addEventListener('input', render);
  filterToEl.addEventListener('change', render);
  filterToEl.addEventListener('input', render);

  clearFiltersEl.addEventListener('click', function () {
    filterCatEl.value = 'all';
    filterFromEl.value = '';
    filterToEl.value = '';
    render();
  });

  render();
})();
</script>
</body>
</html>
